import static org.junit.jupiter.api.Assertions.*;
import java.io.*;
import java.util.*;

public enum OrderStatus {
  PLACED, PREPARING, OUT_FOR_DELIVERY, DELIVERED, CANCELLED
}

class Delivery {
  public int deliveryId;
  public int startMinute;
  public int endMinute;

  public Delivery(int deliveryId, int startMinute, int endMinute){
     this.deliveryId = deliveryId;
     this.startMinute = startMinute;
     this.endMinute = endMinute;
  }

  public int getDurationTimes(){
    return endMinute - startMinute;
  }
}

class Order {
  public int orderId;
  public int restaurantId;
  public int customerId;
  public double orderValue;
  public double distanceKm;
  public OrderStatus status;

  public Order(int orderId, int restaurantId, int customerId, double orderValue, double distanceKm, OrdeStatus status){
     this.orderId = orderId;
     this.restaurantId = restaurantId;
     this.customerId = customerId;
     this.orderValue = orderValue;
     this.distanceKm = distanceKm;
     this.status = status;
  }
}

class OrderStatistics {
  public int totalOrders;
  public int activeOrders;
  public int closedOrders;

  public OrderStatistics(int totalOrders, int activeOrders, int closedOrders){
    this.totalOrders = totalOrders;
    this.activeOrders = activeOrders;
    this.closedOrders = closedOrders;
  }
}

class OrderManager {
   public List<Order> orders;
   public Map<Integer, List<Delivery>> orderDeliveries; // orderId -> List of Deliveries

   public OrderManager(){
      orders = new ArrayList<>();
      orderDeliveries = new HashMap<>();
   }

   public void addOrder(Order order){
      orders.add(order);
   }

   public void addDelivery(int orderId, Delivery delivery){
      boolean exists = false;

       for(Order order: orders){
          if(order.orderId == orderId){
             exists = true;
             break;
          }
       }

       if(!exists) return;
       orderDeliveries.computeIfAbsent(orderId, k -> new ArrayList<>()).add(delivery);
   }

   public Map<Integer, Double> getAverageDeliveryTimeByRestaurant(){
      Map<Integer, Integer> totalDuration = new HashMap<>();
      Map<Integer, Integer> totaCount = new HashMap<>();

      for(Order order : orders){
        if(orderDeliveries.containsKey(order.orderId)){
          for(Delivery delivery: orderDeliveries.get(order.orderId)){
              totalDuration.put(order.restaurantId, totalDuration.getOrDefault(order.restaurantId,0)+delivery.getDurationMinutes());
              totalCount.put(order.restaurantId, totalCount.getOrDefault(order.restaurantId,0)+1);
          }
        }
      }

      Map<Integer, Double> result = new HashMap<>();
      for(Integer restaurantId: totalDuration.keySet()){
        result.put(restaurantId, (double) totalDuration.get(restaurantId)/totalCount.get(restaurantId));
      }
     return result;
   }

   public void updateOrderStatus(int orderId, String newStatus){
      for(Order order: orders){
        if(order.orderId == orderId){
          order.status = OrderStatus.valueOf(newStatus);
          return;
        }
      }
   }

   public OrderStatistics getOrderStats(){
     int total = orders.size();
     int active = 0;

     for(Order order: orders){
       if(order.status == OrderStatus.PLACED
          || order.status == OrderStatus.PREPARING
          || order.status == OrderStatus.OUT_FOR_DELIVERY
        ){
          active++;      
       }     
     }
     int closed = 0;
     for(Order order: orders){
        if(order.status == OrderStatus.DELIVERED 
           || order.status == OrderStatus.CANCELLED){
          closed++;
        }
     }
     return new OrderStatistics(total,active,closed);
   }
}

public class FoodDelivery {
    public static void main(String args[]){
        testOrderManager();
        testGetAverageDeliveryTimeByRestaurant();
    }

    public static void testOrderManager(){
      System.out.println("Running testOrderManager .. ");
      OrderManager orderManager = new OrderManager();
      orderManager.addOrder(new Order(1,10,100,25.0, 3.2, OrderStatus.PLACED));
      orderManager.addOrder(new Order(2,10,101,55.0, 1.4, OrderStatus.PREPARING));
      orderManager.addOrder(new Order(3,11,102,15.0, 6.0, OrderStatus.OUT_OF_DELIVERY));
      orderManager.addOrder(new Order(4,11,103,40.0, 2.0, OrderStatus.DELIVERED));
      orderManager.addOrder(new Order(5,12,104,18.0, 4.5, OrderStatus.CANCELLED));    

      OrderStatistics statistics = orderManager.getOrderStats();
      assertEquals(5, statistics.totalOrders());
      assertEquals(3, statistics.activeOrders());
      assertEquals(2, statistics.closedOrders());

    }

    public static void testGetAverageDeliveryTimeByRestaurant(){
      System.out.println("Running testGetAverageDeliveryTimeByRestaurant .. ");
      OrderManager orderManager = new OrderManager();
      orderManager.addOrder(new Order(1,10,100,25.0, 3.2, OrderStatus.DELIVERED));
      orderManager.addOrder(new Order(2,10,101,55.0, 1.4, OrderStatus.DELIVERED));
      orderManager.addOrder(new Order(3,11,102,15.0, 6.0, OrderStatus.DELIVERED));

      orderManager.addDelivery(new Delivery(101,10, 40));
      orderManager.addDelivery(new Delivery(102,50, 80));
      orderManager.addDelivery(new Delivery(103,90, 150));
      orderManager.addDelivery(new Delivery(104,20, 80));
      orderManager.addDelivery(new Delivery(105, 0, 10));

      Map<Integer, Double> avgTimes = orderManager.getAverageDeliveryTimeByRestaurant();
      assertEquals(40, (double) avgTimes.get(10), 0.0001);
      assertFalse(avgTimes.containsKey(12));    
    }  

}

import java.util.*;
import java.util.stream.Collectors;

enum ProductCategory {
    FRUIT, VEGETABLE, DAIRY, GRAIN, MEAT
}

enum OrderStatus {
    PLACED, COMPLETED, CANCELLED
}

class Product {
    public int productId;
    public String name;
    public double price;
    public ProductCategory category;
    public int stockQty;

    public Product(int productId, String name, double price, ProductCategory category, int stockQty) {
        this.productId = productId;
        this.name = name;
        this.price = price;
        this.category = category;
        this.stockQty = stockQty;
    }

    public double getPrice() {
        return price;
    }

    public int getStockQty() {
        return stockQty;
    }

    public void setStockQty(int qty) {
        this.stockQty = qty;
    }

    @Override
    public String toString() {
        return "Product{id=" + productId + ", name='" + name + "', price=" + price + ", category=" + category + ", stock=" + stockQty + "}";
    }
}

class Customer {
    public int customerId;
    public String name;

    public Customer(int customerId, String name) {
        this.customerId = customerId;
        this.name = name;
    }

    public String getName() {
        return name;
    }

    @Override
    public String toString() {
        return "Customer{id=" + customerId + ", name='" + name + "'}";
    }
}

class CartItem {
    public int productId;
    public int quantity;

    public CartItem(int productId, int quantity) {
        this.productId = productId;
        this.quantity = quantity;
    }
}

class Cart {
    public int customerId;
    public List<CartItem> items;

    public Cart(int customerId) {
        this.customerId = customerId;
        this.items = new ArrayList<>();
    }

    public void addItem(CartItem item) {
        items.add(item);
    }

    public List<CartItem> getItems() {
        return items;
    }
}

class Order {
    public int orderId;
    public int customerId;
    public double totalAmount;
    public OrderStatus status;

    public Order(int orderId, int customerId, double totalAmount, OrderStatus status) {
        this.orderId = orderId;
        this.customerId = customerId;
        this.totalAmount = totalAmount;
        this.status = status;
    }

    public double getTotalAmount() {
        return totalAmount;
    }
}

class StoreStats {
    public int totalProducts;
    public int totalCustomers;
    public double totalSales;

    public StoreStats(int totalProducts, int totalCustomers, double totalSales) {
        this.totalProducts = totalProducts;
        this.totalCustomers = totalCustomers;
        this.totalSales = totalSales;
    }

    @Override
    public String toString() {
        return "StoreStats{totalProducts=" + totalProducts + ", totalCustomers=" + totalCustomers + ", totalSales=" + totalSales + "}";
    }
}

class InventoryManager {
    private List<Product> products;

    public InventoryManager() {
        this.products = new ArrayList<>();
    }

    public void addProduct(Product product) {
        products.add(product);
    }

    public void removeProduct(int productId) {
        products.removeIf(p -> p.productId == productId);
    }

    public void updateStock(int productId, int qty) {
        for (Product p : products) {
            if (p.productId == productId) {
                p.setStockQty(qty);
                break;
            }
        }
    }

    public Product getProductById(int productId) {
        for (Product p : products) {
            if (p.productId == productId) {
                return p;
            }
        }
        return null;
    }

    public List<Product> getLowStockProducts(int threshold) {
        return products.stream()
                .filter(p -> p.getStockQty() < threshold)
                .collect(Collectors.toList());
    }

    public int getTotalProducts() {
        return products.size();
    }
}

class CustomerManager {
    private List<Customer> customers;

    public CustomerManager() {
        this.customers = new ArrayList<>();
    }

    public void addCustomer(Customer customer) {
        customers.add(customer);
    }

    public Customer getCustomerById(int customerId) {
        for (Customer c : customers) {
            if (c.customerId == customerId) {
                return c;
            }
        }
        return null;
    }

    public int getTotalCustomers() {
        return customers.size();
    }
}

class CartManager {
    private Map<Integer, Cart> carts;

    public CartManager() {
        this.carts = new HashMap<>();
    }

    public Cart createCart(int customerId) {
        Cart cart = new Cart(customerId);
        carts.put(customerId, cart);
        return cart;
    }

    public void addToCart(int customerId, CartItem item) {
        Cart cart = carts.get(customerId);
        if (cart != null) {
            cart.addItem(item);
        }
    }

    public void removeFromCart(int customerId, int productId) {
        Cart cart = carts.get(customerId);
        if (cart != null) {
            cart.items.removeIf(ci -> ci.productId == productId);
        }
    }

    public double getCartTotal(int customerId, InventoryManager inventory) {
        Cart cart = carts.get(customerId);
        if (cart == null) return 0.0;
        double total = 0.0;
        for (CartItem ci : cart.getItems()) {
            Product p = inventory.getProductById(ci.productId);
            if (p != null) {
                total += p.getPrice() * ci.quantity;
            }
        }
        return total;
    }
}

class OrderManager {
    private List<Order> orders;
    private double totalSales;

    public OrderManager() {
        this.orders = new ArrayList<>();
        this.totalSales = 0.0;
    }

    public void placeOrder(int orderId, int customerId, double totalAmount) {
        Order order = new Order(orderId, customerId, totalAmount, OrderStatus.PLACED);
        orders.add(order);
        totalSales += totalAmount;
    }

    public void updateOrderStatus(int orderId, OrderStatus status) {
        for (Order o : orders) {
            if (o.orderId == orderId) {
                o.status = status;
                break;
            }
        }
    }

    public StoreStats getStoreStats(int totalProducts, int totalCustomers) {
        return new StoreStats(totalProducts, totalCustomers, totalSales);
    }

    public int getTotalOrders() {
        return orders.size();
    }
}

public class GroceryStore {
    public static void main(String[] args) {
        testInventory();
        testCustomerAndCart();
        testOrderAndStats();
        System.out.println("All tests passed!");
    }

    public static void testInventory() {
        System.out.println("Running testInventory...");
        InventoryManager inv = new InventoryManager();
        Product apple = new Product(1, "Apple", 1.5, ProductCategory.FRUIT, 100);
        inv.addProduct(apple);
        Product found = inv.getProductById(1);
        if (found == null || found.productId != 1) {
            System.out.println("testInventory add/get fail");
        }
        List<Product> lowStock = inv.getLowStockProducts(50);
        if (lowStock.size() != 0) {
            System.out.println("testInventory lowStock fail");
        }
        inv.updateStock(1, 40);
        lowStock = inv.getLowStockProducts(50);
        if (lowStock.size() != 1) {
            System.out.println("testInventory update/lowStock fail");
        }
        if (inv.getTotalProducts() != 1) {
            System.out.println("testInventory total fail");
        }
    }

    public static void testCustomerAndCart() {
        System.out.println("Running testCustomerAndCart...");
        CustomerManager custMgr = new CustomerManager();
        Customer cust = new Customer(101, "John Doe");
        custMgr.addCustomer(cust);
        if (custMgr.getTotalCustomers() != 1 || custMgr.getCustomerById(101).customerId != 101) {
            System.out.println("testCustomer add/get fail");
        }
        InventoryManager inv = new InventoryManager();
        inv.addProduct(new Product(1, "Apple", 1.5, ProductCategory.FRUIT, 100));
        CartManager cartMgr = new CartManager();
        cartMgr.createCart(101);
        cartMgr.addToCart(101, new CartItem(1, 2));
        double total = cartMgr.getCartTotal(101, inv);
        if (Math.abs(total - 3.0) > 0.0001) {
            System.out.println("testCart total fail: " + total);
        }
    }

    public static void testOrderAndStats() {
        System.out.println("Running testOrderAndStats...");
        OrderManager orderMgr = new OrderManager();
        InventoryManager inv = new InventoryManager();
        inv.addProduct(new Product(1, "", 0, null, 0));
        CustomerManager custMgr = new CustomerManager();
        custMgr.addCustomer(new Customer(101, ""));
        CartManager cartMgr = new CartManager();
        cartMgr.createCart(101);
        orderMgr.placeOrder(1, 101, 10.0);
        if (orderMgr.getTotalOrders() != 1) {
            System.out.println("testOrder total fail");
        }
        StoreStats stats = orderMgr.getStoreStats(1, 1);
        if (stats.totalSales != 10.0) {
            System.out.println("testStats sales fail");
        }
        orderMgr.updateOrderStatus(1, OrderStatus.COMPLETED);
    }
}

