import java.time.LocalDate;
import java.util.Arrays;
import java.util.List;
import java.uitl.stream.Collectors;

public class Member {
  private String name;
  private String membershipType; // Basic, Premium
  private double monthlyFee;
  private LocalDate expiryDate;

  public Member(String name, String mType, double mFee, LocalDate expiryDate){
      this.name = name;
      this.membershipType = mType;
      this.monthlyFee = mFee;
      this.expiryDate = expiryDate;
  }

  public String getName(){
    return name;
  }

  public String getMembershipType(){
    return membershipType;
  }

  public double getMonhtlyFee(){
    return monthlyFee;
  }

  public LocalDate getExpiryDate(){
    return expiryDate;
  }

  public isActive(){
      return expiryDate.isAfter(LocalDate.now());
  }

  @Override
  public String toString(){
    return String.format("%s (%s) - Expires: %s", name, membershipType, expiryDate);
  }
}

import java.util.List;
import java.util.stream.Collectors;

import Member;

public class GymManagementService{
    public List<Member> getActiveMembers(List<Member> gymMembers){
      return gymMembers.stream().filter(Member::isActive).collect(Collectors.toList());
    }

    public double getTotalMonthlyPremiumRevenue(List<Member> gymMembers){
      return gymMembers.stream().filter(m -> "Premium".equals(m.getMembershipType()).mapToDouble(Member::getMonthlyFee).sum();
    }

    public String getExpiredMembers(List<Member> gymMembers){
      return gymMembers.stream().filter(m -> !m.isActive()).map(Member::getName).collect(Collectors.joining(", "));
    }
}

